import{_ as a,c as l,o as n,aG as t,aY as i}from"./chunks/framework.DT95gh_o.js";const u=JSON.parse('{"title":"B 端性能优化","description":"","frontmatter":{},"headers":[],"relativePath":"special/mid-end/optimized/index.md","filePath":"special/mid-end/optimized/index.md"}'),s={name:"special/mid-end/optimized/index.md"};function r(o,e,p,c,d,h){return n(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="b-端性能优化" tabindex="-1">B 端性能优化 <a class="header-anchor" href="#b-端性能优化" aria-label="Permalink to “B 端性能优化”">​</a></h1><h2 id="网页指标" tabindex="-1">网页指标 <a class="header-anchor" href="#网页指标" aria-label="Permalink to “网页指标”">​</a></h2><blockquote><p><a href="https://web.dev/articles/vitals?hl=zh-cn" target="_blank" rel="noreferrer">Web Vitals</a></p></blockquote><p>前端的网站优化目标基本聚焦在更快的显示、操作稳定页面，通过技术手段去无限拉近与原生应用的体验。核心指标一般是三个</p><ul><li><strong>Largest Contentful Paint (LCP)</strong> ：衡量加载性能。为了提供良好的用户体验，应在网页首次开始加载的 2.5 秒内完成 LCP。</li><li><strong>Interaction to Next Paint (INP)</strong> ：衡量互动性。为了提供良好的用户体验，网页的 INP 应不超过 200 毫秒。</li><li><strong>Cumulative Layout Shift (CLS)</strong> ：衡量视觉稳定性。为了提供良好的用户体验，网页的 CLS 应保持在 0.1 或更低。</li></ul><p><img src="'+i+`" alt="web-vitals-timeline.png"></p><p>对于我们当前的微前端重型 B 端平台来说，从用户敲下 <code>URL</code> 到可操作的过程中，可控制的范围很有限。上下游 <code>CDN</code>、网关、基建超出我们的控制范围， 我们能做的集中在子应用的加载上，因此重点指标是追求 <code>TTFB</code> ~ <code>LCP</code> 的时间。</p><h2 id="通用优化" tabindex="-1">通用优化 <a class="header-anchor" href="#通用优化" aria-label="Permalink to “通用优化”">​</a></h2><p>老生都不谈的优化方式就不说了， <a href="https://developer.yahoo.com/performance/rules.html" target="_blank" rel="noreferrer">雅虎军规</a> 还是具有指导意义的，但是很多随着现代前端工程化的实现，意义已经没那么大了。</p><ul><li>最小化网络请求， 限制 http 数量 <ul><li>h2 通过多路复用已经不再限制并发数，之前都是通过泛域名来解决</li></ul></li><li>优化资源加载顺序 <ul><li>CSS 在顶部JS在底部已经成了框架的默认配置</li></ul></li><li>缓存与压缩 <ul><li>Expires或Cache-Control头，并启用 <code>Gzip</code> 压缩</li></ul></li><li>引入 CDN</li><li>其他 <ul><li>减少DOM元素数量、</li><li>使Ajax可缓存、</li><li>延迟加载组件、</li><li>避免重定向和404错误</li><li>...</li></ul></li></ul><h2 id="方法论" tabindex="-1">方法论 <a class="header-anchor" href="#方法论" aria-label="Permalink to “方法论”">​</a></h2><p>我们可以简单的写出优化公式： <code>时间 = 大小 / 速度</code>， 那么就可以得出这么几个方向</p><h3 id="提高速度" tabindex="-1">提高速度 <a class="header-anchor" href="#提高速度" aria-label="Permalink to “提高速度”">​</a></h3><p><strong>以空间换时间——Cache</strong></p><p>可以针对一些变化不高的资源，如菜单、用户信息、权限列表等接口信息进行本地缓存，后续接口得到新值时再进行替换。</p><p><strong>同步串行改异步并发</strong></p><ul><li>代码支持更多空状态，增强鲁棒性，结合 Cache 可以让子应用可以和主应用的依赖接口进行并发，从串行依赖改为并行的多状态。如权限接口一般阻塞加载子应用，但可以默认视为无权限并行子应用，等权限接口回来再修改状态。</li><li>菜单、导航等均可拆分异步子模块从而减少主应用大小，提前子应用加载时机。</li><li><code>React.lazy</code> 异步组件</li><li><code>Promise</code> 异步逻辑</li></ul><p><strong>减少React渲染</strong></p><p>使用 <a href="https://www.yuque.com/hlwzn/hi5s1y/qknnb4gpf8tfaheh" target="_blank" rel="noreferrer">全局状态 + 状态提示</a> 减少状态复杂度，减少无意义顶层渲染。</p><p>如 Layout</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>function Layout(){</span></span>
<span class="line"><span>    /** 此处不应写任何状态，导致重渲染 */</span></span>
<span class="line"><span>    return &lt;&gt;</span></span>
<span class="line"><span>        &lt;Auth /&gt; // 通过全局状态仅让末级组件渲染</span></span>
<span class="line"><span>        &lt;Menu /&gt;</span></span>
<span class="line"><span>        &lt;Nav /&gt;</span></span>
<span class="line"><span>        &lt;Outlet /&gt;</span></span>
<span class="line"><span>    &lt;/&gt;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p><strong>合并缓存请求</strong></p><ul><li><a href="https://tanstack.com/query/" target="_blank" rel="noreferrer">useQuery</a> 王炸</li></ul><p><strong>SSR/SSG</strong></p><p>B端平台大部分是实时动态数据，会进一步增加服务器负载，提升有限。</p><p><strong>静态资源 &amp; CDN</strong></p><ul><li>图片使用更高压缩率的 WebP，减少字体使用，约束标准字体为三种（数字、特殊、正文）。</li><li>按需加载，<a href="https://segmentfault.com/a/1190000046453750?utm_source=sf-similar-article" target="_blank" rel="noreferrer">IntersectionObserver + setTimeout</a> 懒加载图片</li><li>静态资源统统上CDN</li></ul><p><strong>Node版本</strong></p><p>新版 node 一般都带来更好的性能。升级后对比构建产物一致就不会有问题。</p><p><strong>合适的打包策略</strong></p><ul><li>公共依赖一般不变可以打包在一起</li><li>按路由-&gt;页面打包做到页面按需加载，使用对应组件路径命名可以利于线上事故排查</li></ul><h3 id="减小大小" tabindex="-1">减小大小 <a class="header-anchor" href="#减小大小" aria-label="Permalink to “减小大小”">​</a></h3><p><strong>构建产物分析</strong></p><p>推荐 <code>rsdoctor</code>，基于 <code>webpack-bundle-analyzer</code> 封装，信息更全面，可以找到很多没用到却打包进来的产物，多半是因为没有<strong>tree shaking</strong>。</p><p><strong>tree shaking</strong></p><ul><li>尽量使用<code>命名导入</code>，很多都是因为使用<code>默认导入</code>而被整体打包，如 <code>import _ from &#39;lodash&#39;</code>。</li><li>不要从 <code>antd/lib</code> 导入，也会导致全量打包, 可以从 <code>antd/es</code> 导入</li><li>循环依赖也会破坏<strong>tree shaking</strong>，可以通过 <code>npx madge --circular src/**/*</code> 来查找</li><li>减少引入未使用的代码， 如 <code>oneApi</code> 未使用的请求</li></ul><p><strong>减少调整依赖库</strong></p><ul><li>很多库已经过时或者能力已被现代js支持，可以参考 <code>https://e18e.dev/docs/replacements/</code>。</li><li><code>AntDesign</code> 的 <a href="https://ant-design.antgroup.com/components/space-cn" target="_blank" rel="noreferrer">Space组件</a> 会增加很多 Dom 层级， <code>Flex</code> 的 <code>Gap</code> 就能搞定间距。</li><li>使用 <code>npx depcheck</code> 检查没用到的包</li><li>调整依赖，如 <code>@types -&gt; devDependencies</code>，减少安装时间</li></ul><p><strong>qiankun3依赖复用</strong></p><p>分析提取子应用共有依赖进行打包，其他子应用加载等于直接用缓存。</p><h3 id="减少感知时间" tabindex="-1">减少感知时间 <a class="header-anchor" href="#减少感知时间" aria-label="Permalink to “减少感知时间”">​</a></h3><blockquote><p>时间也可以被欺骗</p></blockquote><ul><li>大背景图可以先用类似颜色的 css 填充，基本看不出来</li><li>使用 <a href="https://ant-design.antgroup.com/components/skeleton-cn" target="_blank" rel="noreferrer">Skeleton 骨架屏</a></li><li>SPA + 快照 === 0s 加载</li></ul>`,43)])])}const m=a(s,[["render",r]]);export{u as __pageData,m as default};
